// Combina la lista de tareas de la sección de Asana con los presupuestos
// ya existentes en Supabase (asana_gid no nulo) para que el front pueda
// distinguir tareas nuevas (importables) de tareas ya importadas
// (refrescables).
const asanaResp = $('GET Asana Section').first().json || {};
const tasks = Array.isArray(asanaResp.data) ? asanaResp.data : (Array.isArray(asanaResp) ? asanaResp : []);

const supaItems = $input.all() || [];
let presupuestos = [];
for (const it of supaItems) {
  const j = it.json;
  if (!j) continue;
  if (Array.isArray(j)) presupuestos = presupuestos.concat(j);
  else if (j.id) presupuestos.push(j);
  else if (Array.isArray(j.data)) presupuestos = presupuestos.concat(j.data);
}
const gidToPres = {};
presupuestos.forEach(p => { if (p && p.asana_gid) gidToPres[String(p.asana_gid)] = p; });

function parseHoras(s) {
  if (!s) return 0;
  const m = String(s).match(/(\d+)\s*h/i);
  return m ? Math.min(parseInt(m[1], 10) || 0, 10000) : 0;
}
function parseCliente(tags) {
  const t = (tags || []).find(x => x && x.name && /^cliente\s*:/i.test(x.name));
  if (!t) return 'Sin cliente';
  return String(t.name).replace(/^cliente\s*:\s*/i, '').trim() || 'Sin cliente';
}

const out = tasks.map(t => {
  const cf = {};
  (t.custom_fields || []).forEach(c => { if (c && c.name) cf[c.name] = c.display_value; });
  const existing = gidToPres[String(t.gid)] || null;
  return {
    gid: String(t.gid),
    name: t.name || '',
    permalink_url: t.permalink_url || null,
    completed: !!t.completed,
    cliente: parseCliente(t.tags),
    horas_estimadas: parseHoras(cf['Estimated time']),
    coste_cf: cf['Coste'] || null,
    estado_pres_cf: cf['Estado del prespuesto'] || null,
    mail_cliente: cf['Mail cliente'] || null,
    ya_importado: !!existing,
    presupuesto_id: existing ? existing.id : null,
    numero_doc:    existing ? existing.numero_doc : null,
    estado_pres:   existing ? existing.estado : null
  };
});

// Nuevas primero (más útil en la UI), luego ya importadas.
out.sort((a, b) => {
  const ax = a.ya_importado ? 1 : 0;
  const bx = b.ya_importado ? 1 : 0;
  if (ax !== bx) return ax - bx;
  return String(a.name).localeCompare(String(b.name));
});

return [{ json: {
  tareas: out,
  total: out.length,
  nuevas: out.filter(t => !t.ya_importado).length,
  importadas: out.filter(t => t.ya_importado).length,
  seccion_gid: '1210961912211323'
} }];

// Valida el body de import/refresh:
//   { action: 'import'|'refresh', asana_gid: '12345...' }
const raw = $input.first().json || {};
const b = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const action = String(b.action || '').toLowerCase();
const asana_gid = String(b.asana_gid || '').trim();
const errores = [];
const VALID = ['import', 'refresh'];
if (!VALID.includes(action)) errores.push('action inválida: ' + action + ' (debe ser import|refresh)');
if (!asana_gid)                errores.push('asana_gid obligatorio');
if (asana_gid && !/^\d{6,}$/.test(asana_gid)) errores.push('asana_gid debe ser numérico');
if (errores.length) {
  return [{ json: { __error: true, __errores: errores, __action: action } }];
}
return [{ json: { action, asana_gid } }];

// Mapea la tarea de Asana a un payload de presupuesto y arma el método
// HTTP + query-string que se pasa al endpoint PostgREST de Supabase.
//
//   import   → POST plano. UNIQUE (asana_gid) bloqueará re-importaciones.
//   refresh  → PATCH ?asana_gid=eq.<gid>. Sólo refresca los campos
//              derivables de la descripción (contexto/objetivo/alcance/
//              funcionamiento_esperado/aprobacion + notas + cliente +
//              desarrollo). NO toca estado, horas, costes ni flags: eso
//              lo gestiona el usuario desde la UI y no queremos pisarlo.
const taskResp = $input.first().json || {};
const task = taskResp.data || taskResp;
const prep = $('Preparar').first().json || {};
if (prep.__error) {
  return [{ json: { __error: true, __errores: prep.__errores, __action: prep.__action } }];
}
const action = prep.action;
const now = new Date().toISOString();
const errores = [];
if (!task || !task.gid) {
  errores.push('Asana no devolvió la tarea (gid ' + prep.asana_gid + ')');
  return [{ json: { __error: true, __errores: errores, __action: action } }];
}

// 1) Cliente desde tag "Cliente: XXX"
let cliente = 'Sin cliente';
const tagCli = (task.tags || []).find(t => t && t.name && /^cliente\s*:/i.test(t.name));
if (tagCli) cliente = String(tagCli.name).replace(/^cliente\s*:\s*/i, '').trim() || 'Sin cliente';

// 2) Desarrollo: name sin prefijo "(Pagado)" / "(Pago)"
const rawName = String(task.name || '').replace(/^\s*\(\s*Pagad[oa]?\s*\)\s*/i, '').trim();
const desarrollo = rawName || '(sin título)';

// 3) Custom fields como dict
const cf = {};
(task.custom_fields || []).forEach(c => { if (c && c.name) cf[c.name] = c.display_value; });

// 4) horas_cliente desde "Estimated time" (formato "26h 00m")
let horas_cliente = 0;
if (cf['Estimated time']) {
  const m = String(cf['Estimated time']).match(/(\d+)\s*h/i);
  if (m) horas_cliente = Math.min(parseInt(m[1], 10) || 0, 10000);
}

// 5) quien_abona: "(Pagado)" en el nombre o Coste="Con coste" → cliente
const quien_abona = (/pagad/i.test(task.name || '') || /con coste/i.test(String(cf['Coste']||''))) ? 'cliente' : 'yurest';

// 6) entorno: heurística por keywords. Default backoffice.
const lc = ((task.name||'') + ' ' + String(task.notes||'').slice(0,500)).toLowerCase();
let entorno = 'backoffice';
if (/\bapp\b|m[oó]vil|notificaci[oó]n|tpv/i.test(lc) && !/back ?office/i.test(lc)) entorno = 'app_cliente';

// 7) Parseo de la descripción por secciones
function clip(s) { const v = String(s || '').trim(); return v || null; }
const notes = String(task.notes || '');
const sec = {};
const mTarea = notes.match(/## .*TAREA([\s\S]*?)(?=\n\s*Comportamiento actual:|\n\s*Comportamiento esperado:|\n\s*✅|$)/i);
if (mTarea) sec.contexto = clip(mTarea[1]);
const mAct = notes.match(/Comportamiento actual:\s*([\s\S]*?)(?=\n\s*Comportamiento esperado:|\n\s*✅|$)/i);
if (mAct) sec.alcance = clip(mAct[1]);
const mEsp = notes.match(/Comportamiento esperado:\s*([\s\S]*?)(?=\n\s*✅|$)/i);
if (mEsp) sec.funcionamiento_esperado = clip(mEsp[1]);
const mCrit = notes.match(/✅\s*CRITERIOS DE ACEPTACI[ÓO]N\s*([\s\S]*)$/i);
if (mCrit) sec.aprobacion = clip(mCrit[1]);
if (sec.contexto) {
  const mPara = sec.contexto.match(/^Para\s+.+$/m);
  if (mPara) sec.objetivo = clip(mPara[0]);
}

// 8) `notas`: permalink + mail + traza de origen
const notasArr = [];
if (task.permalink_url) notasArr.push(task.permalink_url);
if (cf['Mail cliente'])  notasArr.push('Mail cliente: ' + cf['Mail cliente']);
notasArr.push('Importado de Asana (gid ' + task.gid + ')');
const notasStr = notasArr.join('\n');

function genUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c){
    const r = Math.random()*16|0; return (c==='x'?r:(r&0x3)|0x8).toString(16);
  });
}

let payload, __method, __qs;
if (action === 'import') {
  payload = {
    id: genUUID(),
    asana_gid: String(task.gid),
    cliente,
    desarrollo,
    entorno,
    quien_abona,
    estado: 'en_espera',
    estado_entrega: 'pendiente',
    enviado: false,
    horas_yurest: 0,
    horas_cliente,
    coste_yurest: 0,
    coste_cliente: 0,
    coste_hora_yurest: 25.00,
    coste_hora_cliente: 85.00,
    descuento_pct: 0,
    notas: notasStr,
    contexto: sec.contexto || null,
    objetivo: sec.objetivo || null,
    alcance:  sec.alcance  || null,
    funcionamiento_esperado: sec.funcionamiento_esperado || null,
    entregables: null,
    presupuesto_detalle: null,
    aprobacion: sec.aprobacion || null,
    created_at: now,
    updated_at: now
  };
  __method = 'POST';
  __qs = '';
} else { // refresh: sólo campos derivables de la descripción, sin pisar estado del usuario.
  payload = {
    cliente,
    desarrollo,
    notas: notasStr,
    contexto: sec.contexto || null,
    objetivo: sec.objetivo || null,
    alcance:  sec.alcance  || null,
    funcionamiento_esperado: sec.funcionamiento_esperado || null,
    aprobacion: sec.aprobacion || null,
    updated_at: now
  };
  __method = 'PATCH';
  __qs = 'asana_gid=eq.' + encodeURIComponent(String(task.gid));
}

return [{ json: Object.assign({}, payload, {
  __method, __qs,
  __task_gid: String(task.gid),
  __task_name: task.name || '',
  __task_url:  task.permalink_url || null,
  __action: action
}) }];

// Extrae el presupuesto resultante del upsert y prepara el comentario
// que se publicará en Asana. El comment va siempre (sea import o
// refresh): así Asana queda con traza de cada operación.
const mapped = $('Mapear').first().json || {};
if (mapped.__error) {
  return [{ json: { __skip_comment: true, __error: true, __errores: mapped.__errores || ['error en mapeo'] } }];
}
const items = $input.all() || [];
let row = null;
const errPostgrest = [];
for (const it of items) {
  const j = it.json; if (!j) continue;
  if (Array.isArray(j)) {
    if (j[0] && j[0].id) { row = j[0]; break; }
  } else if (j.id) {
    row = j; break;
  } else if (Array.isArray(j.data) && j.data[0]) {
    row = j.data[0]; break;
  } else if (j.code && j.message) {
    errPostgrest.push(j.message + (j.details ? ' (' + j.details + ')' : ''));
  }
}
if (!row) {
  // Caso típico: import sobre asana_gid duplicado → PostgREST devuelve
  // 409 conflict (code 23505 unique_violation). Mensaje claro al front.
  const msg = errPostgrest.length ? errPostgrest.join('; ') : 'PostgREST devolvió 0 filas';
  const dup = /duplicate key|unique/i.test(msg);
  return [{ json: { __skip_comment: true, __error: true, __errores: [dup ? 'Esta tarea ya está importada (asana_gid duplicado). Usa Refrescar.' : msg] } }];
}
const numero = row.numero_doc || '(sin número)';
const fecha = new Date().toISOString().slice(0,10);
const accion = mapped.__action === 'refresh' ? 'Refrescado desde Asana' : 'Importado al portal';
const texto = '[Yurest Portal] ' + accion + ' como ' + numero + ' el ' + fecha + '.';
return [{ json: {
  __task_gid: mapped.__task_gid,
  __task_name: mapped.__task_name,
  __action: mapped.__action,
  presupuesto: row,
  comment_text: texto
} }];

// Junta el resultado del upsert con el del comment de Asana y monta
// el shape contractual { success, presupuesto, errores, ... }.
const mapped = $('Mapear').first().json || {};
const prepCom = $('Preparar comentario').first().json || {};
if (mapped.__error) {
  return [{ json: { success: false, presupuesto: null, asana_gid: null, action: mapped.__action || null, errores: mapped.__errores || ['error en mapeo'] } }];
}
if (prepCom.__error) {
  return [{ json: { success: false, presupuesto: null, asana_gid: mapped.__task_gid || null, action: mapped.__action || null, errores: prepCom.__errores || ['no se pudo guardar en Supabase'] } }];
}
// El comment de Asana es best-effort: si falló (continueOnFail), no
// rompemos la importación. Detectamos errores del comment para reportar.
const commentResp = ($input.first() || {}).json || {};
const commentOk = !!(commentResp && (commentResp.data || commentResp.gid));
const warns = [];
if (!commentOk) warns.push('No se pudo publicar el comentario en Asana (la importación sí se guardó).');

return [{ json: {
  success: true,
  presupuesto: prepCom.presupuesto,
  asana_gid: mapped.__task_gid,
  action: mapped.__action,
  comentario_enviado: commentOk,
  errores: [],
  warnings: warns
} }];
